member.example:
Format any ViewModel value as text without knowing its exact type at compile time.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private TMP_Text _label;
        
        private AnyToStringCasterBinder Score => new(
            value => _label.text = value);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public int _score;
    }

Format a float ViewModel value with a specific number format before displaying it.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private TMP_Text _label;
        
        private GenericToStringCasterBinder<float> Distance => new(
            value => _label.text = value, "F1");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _distance;
    }

Show a warning panel when a ViewModel error message is non-empty.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private GameObject _warningPanel;
        
        private StringToBoolCasterBinder ErrorMessage => new(
            value => _warningPanel.SetActive(value),
            isInvert: true);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _errorMessage;
    }
